func Solve(s string) string { sign:=""; if strings.HasPrefix(s,"-")||strings.HasPrefix(s,"+") {sign=s[:1]; s=s[1:]}; frac:=""; if i:=strings.Index(s,"."); i>=0 {frac=s[i:]; s=s[:i]}; return sign+comma(s)+frac }

